=Answer this security questionnaire question:

Question: {{ $json.question }}
Question Category: {{ $json.category || 'General' }}
Framework: {{ $json.framework || 'General' }}
Requested by: {{ $json.requestor_org }}

---
COMPANY DOCUMENTATION:
{{ $json.policy_content || 'No specific policy documentation loaded. Use general cybersecurity MSSP best practices.' }}
---

Answer the question based ONLY on the documentation above.

parameters.jsCode:
const raw = $input.first().json.message.content;
let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  const cleaned = raw.replace(/```json\n?|```/g, '').trim();
  parsed = JSON.parse(cleaned);
}
const prev = $input.first().json;
return [{
  json: {
    questionnaire_id: prev.questionnaire_id,
    question_id: prev.question_id,
    question: prev.question,
    answer: parsed.answer,
    confidence: parsed.confidence,
    source_reference: parsed.source_reference,
    follow_up_needed: parsed.follow_up_needed,
    follow_up_note: parsed.follow_up_note
  }
}];

// Collect all answered questions into a formatted response document
const items = $input.all();
const questionnaire_id = items[0].json.questionnaire_id;
const flagged = items.filter(i => i.json.follow_up_needed);

let responseText = `VAKROS SECURITY QUESTIONNAIRE RESPONSE\nGenerated: ${new Date().toISOString()}\n\n`;

items.forEach((item, idx) => {
  const q = item.json;
  responseText += `Q${idx + 1}: ${q.question}\n`;
  responseText += `A: ${q.answer}\n`;
  responseText += `[Confidence: ${q.confidence} | Source: ${q.source_reference}]\n`;
  if (q.follow_up_needed) responseText += `⚠ FOLLOW-UP REQUIRED: ${q.follow_up_note}\n`;
  responseText += '\n';
});

if (flagged.length > 0) {
  responseText += `\n--- ITEMS REQUIRING MANUAL REVIEW (${flagged.length}) ---\n`;
  flagged.forEach((item, i) => {
    responseText += `${i+1}. ${item.json.question}: ${item.json.follow_up_note}\n`;
  });
}

return [{
  json: {
    questionnaire_id,
    ai_response: responseText,
    total_questions: items.length,
    high_confidence: items.filter(i => i.json.confidence === 'high').length,
    follow_ups_needed: flagged.length,
    status: 'completed'
  }
}];
